18	
19	------------------------------------------------------------------------------
20	-- Package Header
21	------------------------------------------------------------------------------
22	package top_tb_pkg is
23	
24		-------------------------------------------------------------------------
25		-- TB Definitions
26		-------------------------------------------------------------------------
27		constant 	ClockFrequency_c	: real 		:= 160.0e6;
28		constant	ClockPeriod_c		: time		:= (1 sec)/ClockFrequency_c;
29	
30		-------------------------------------------------------------------------
31		-- Constants
32		-------------------------------------------------------------------------
33		constant InputWidth_c		: integer		:= 16;
34		constant NumOfInputs_c		: integer		:= 4;
35		constant TriggerInputs_c	: integer		:= 4;
36		
37		-------------------------------------------------------------------------
38		-- Variables
39		-------------------------------------------------------------------------
40		shared variable PatternCnt_v	: integer	:= 0;
41		shared variable MemoryDepth_v	: integer		:= 30;
42															
43		-------------------------------------------------------------------------
44		-- Types
45		-------------------------------------------------------------------------	
46		type Data_t is array(natural range <>) of std_logic_vector(InputWidth_c-1 downto 0);	
47		
48		type In_t is record
49			In_Data 	: Data_t(NumOfInputs_c-1 downto 0);
50			In_Vld		: std_logic;
51			Trig_In		: std_logic_vector(TriggerInputs_c-1 downto 0);
52		end record;
53		
54		type Out_t is record
55			Done_Irq	: std_logic;
56			Trig_Out    : std_logic;
57		end record;
58		
59		-------------------------------------------------------------------------
60		-- Procedure
61		-------------------------------------------------------------------------	
62		procedure InputSamples(			samples 	: in	integer;
63								signal	inp			: out	In_t;
64								signal 	clk			: in	std_logic;
65										startCnt	: in	integer := -1;
66										trigAt		: in	integer := -1;
67										dutycycle	: in	integer := 1;
68										trigIdx		: in	integer := 0);
69										
70		procedure CheckData(			samples		: in 	integer;
71										startValue	: in 	integer;
72								signal 	ms			: out	axi_ms_r;
73								signal 	sm			: in	axi_sm_r;
74								signal 	aclk		: in	std_logic);
75								
76		procedure InputSamplesNoCh(		samples 	: in	integer;
77								signal	inp			: out	In_t;
78								signal 	clk			: in	std_logic;
79										startCnt	: in	integer := -1000000;
80										chStep		: in	integer := 1;
81										cntStep		: in	integer := 1);
82										
83		procedure CheckDataNoCh(		samples		: in 	integer;
84										startValue	: in 	integer;
85										chStep		: in	integer := 1;	
86										cntStep		: in	integer := 1;
87								signal 	ms			: out	axi_ms_r;
88								signal 	sm			: in	axi_sm_r;
89								signal 	aclk		: in	std_logic);
90	
91		
92	end top_tb_pkg;
93	
94	package body top_tb_pkg is
95		procedure InputSamples(			samples 	: in	integer;
96								signal	inp			: out	In_t;
97								signal 	clk			: in	std_logic;
98										startCnt	: in	integer := -1;
99										trigAt		: in	integer := -1;
100										dutycycle	: in	integer := 1;
101										trigIdx		: in	integer := 0) is
102			variable Data 	: unsigned(InputWidth_c-1 downto 0);
103		begin
104			if startCnt >= 0 then
105				PatternCnt_v := startCnt;
106			end if;
107			wait until rising_edge(Clk);
108			for cnt in 0 to samples-1 loop
109				--Data := to_unsigned(startCnt+cnt, InputWidth_c);
110				Data := to_unsigned(PatternCnt_v, InputWidth_c);
111				PatternCnt_v := PatternCnt_v+1;
112				-- Apply channel offs
113				for d in 0 to NumOfInputs_c-1 loop
114					Data(Data'left downto Data'left-2) := to_unsigned(d, 3);
115					inp.In_Data(d) <= std_logic_vector(Data);
116				end loop;
