	procedure InputSamples(			samples 	: in	integer;
							signal	inp			: out	In_t;
							signal 	clk			: in	std_logic;
									startCnt	: in	integer := -1;
									trigAt		: in	integer := -1;
									dutycycle	: in	integer := 1;
