		variable Data 	: unsigned(InputWidth_c-1 downto 0);
	begin
		if startCnt >= 0 then
			PatternCnt_v := startCnt;
		end if;
		wait until rising_edge(Clk);
		for cnt in 0 to samples-1 loop
			--Data := to_unsigned(startCnt+cnt, InputWidth_c);
